import { Toast } from 'vant';
import api from './service/api'

export const  lowDevice = () => {
  const ua = navigator.userAgent;

  const deviceInfo = {
    os: "Unknown",
    version: "Unknown"
  };

  if (/android/i.test(ua)) {
    deviceInfo.os = "Android";
    const match = ua.match(/Android\s([0-9.]+)/);
    deviceInfo.version = match ? match[1] : "Unknown";
  }
  console.log('deviceInfo', deviceInfo)
  if(deviceInfo.os === 'Android' && Number(deviceInfo.version.split('.')[0]) < 9) {
      return true

  }

  return false;
}



export const imgClip = ({imgUrl, success}: {imgUrl: string, success: (s: string) => void}) => {
  const img = new Image();
  
  img.onload = function () {
    // 目标宽高比
    const targetRatio = 5 / 4;
    // 图片的宽高比
    const imgRatio = img.width / img.height;
  
    let cropWidth, cropHeight;
    let x = 0, y = 0; // 图片内部的起始坐标
  
    // 比较宽高比，计算裁剪的宽度和高度
    if (imgRatio > targetRatio) {
      cropHeight = img.height;
      cropWidth = cropHeight * targetRatio;
      x = (img.width - cropWidth) / 2;
      y = 0;
    } else {
      cropWidth = img.width;
      cropHeight = cropWidth / targetRatio;
      x = 0;
      y = (img.height - cropHeight) / 2;
    }
  
    // 创建一个新的 canvas 元素
    const canvas = document.createElement('canvas');
  
    // 设置 canvas 的宽高
    canvas.width = cropWidth;
    canvas.height = cropHeight;
  
    // 获取 canvas 的 2D 渲染上下文
    const ctx = canvas.getContext('2d') as CanvasRenderingContext2D;
  
    // 在 canvas 上绘制裁剪后的图片
    ctx.drawImage(img, x, y, cropWidth, cropHeight, 0, 0, cropWidth, cropHeight);
    // 将 canvas 导出为 base64 格式的图片
      const base64Image = canvas.toDataURL('image/png');
      if (success) {
        success(base64Image);
      }
  }
  img.crossOrigin = 'anonymous';
  img.src = imgUrl;
}


// 分享微信小程序到微信好友
export const sendToWechat = async ({ hdImageUrl, params }: { hdImageUrl: string; params: any }) => {
  const r = await api.getWechatShareInfo(params)
  const info = r.data.data
  window.ConnectWebViewBridgeSDK.getAppInstalled(res => {
    if (res.weChat === 'installed') {
      imgClip({imgUrl: hdImageUrl, success: (imgBase64) => {
        const params = {
          userName: process.env.VUE_APP_XIAOCHENGXU_ID,
          path: atob(info.share_url),
          miniProgramType: +process.env.VUE_APP_XIAOCHENGXU_TYPE, // 小程序的版本 0 正式，1开发，2体验
          shareTitle: info.title,
          shareContent: '',
          webpageUrl: 'https://smartxes.tal.com/',
          withShareTicket: true,
          hdImageBase64String: imgBase64
        }
        console.log('调分享微信小程序的参数：', params)
        window.ConnectWebViewBridgeSDK.shareMiniProgram2WX(params)
      } })
    } else {
      // 未安装微信时，提示用户
      Toast({
        message: '当前设备未安装微信App',
        className: 'xpp-h5-toast'
      })
    }
  })
}
// 分享图片到微信朋友圈
